import React,{ useState } from "react";
import {slideInLeft, slideInRight} from "react-animations";
import styled, { keyframes } from 'styled-components';
import axios from 'axios';
const Contact = () => {
    const SlideInLeft = styled.div`animation: 2s ${keyframes`${slideInLeft}`} infinite `;
    const SlideInRight = styled.div`animation: 2s ${keyframes`${slideInRight}`} infinite `;
    const [state, setState] = useState({
        name: '',
        email: '',
        message: ''
    });

    const [result, setResult] = useState(null);

    const handleSubmit = event => {
        event.preventDefault();

        axios
            .post('/send',
                { ...state }
                )
            .then(response => {
                console.log("+_+_+__AXIOS__+_+_+");
                console.log(response.data);
                setResult(response.data);
                setState({
                    name: '',
                    email: '',
                    message: ''
                });
            })
            .catch((err) => {
                console.log("+_+_+__AXIOS__+_+_+");
                console.error("Error response:");
                console.error(err.response.data);    // ***
                console.error(err.response.status);  // ***
                console.error(err.response.headers); // ***
                setResult({
                    success: false,
                    message: 'Something went wrong!'
                });
            });
    };

    const onInputChange = event => {
        const { name, value } = event.target;
        setState({
            ...state,
            [name]: value
        });
    };

    return(
        <div>
            {result && (
                <p className={`${result.success ? 'success' : 'error'}`}>
                    {result.message}
                </p>
            )}
        <div className="ui center aligned segment">
            <h1 className="ui header" style={{fontWeight:"900"}} id="contact">
                <SlideInLeft style={{display:"inline-block"}}>
                    <i className="caret right icon" style={{textAlign:"left",fontSize:"1em"}}/>
                </SlideInLeft>
                Contact
                <SlideInRight style={{display:"inline-block"}}>
                    <i className="caret left icon" style={{textAlign:"right",fontSize:"1em"}}/>
                </SlideInRight>
            </h1>
        </div>
        <div className="ui segment">
            <form className="ui form" id="contact-form" method="POST" onSubmit={handleSubmit}>
                <div className="field">
                    <label htmlFor="name">Name</label>
                    <input name="name" type="text" className="form-control" value={state.name} placeholder="Full Name" onChange={onInputChange}/>
                </div>
                <div className="field">
                    <label htmlFor="email">Email address</label>
                    <input name="email" type="email" className="form-control" value={state.email} aria-describedby="emailHelp" placeholder="Email" onChange={onInputChange}/>
                </div>
                <div className="field">
                    <label htmlFor="message">Message</label>
                    <textarea name="message" className="form-control" rows="5" value={state.message} onChange={onInputChange}></textarea>
                </div>
                <button type="submit" className="ui inverted green button">Submit</button>
            </form>
        </div>
        </div>
    );
};
export default Contact;
